#define SQLITE_OK 0
#define SQLITE_ROW 100
#define SQLITE_DONE 101
#define SQLITE_INTEGER 1
#define SQLITE_FLOAT 2
#define SQLITE_TEXT 3
#define SQLITE_BLOB 4
#define SQLITE_NULL 5
#define SQLITE_OPEN_READWRITE 0x00000002
#define SQLITE_OPEN_CREATE 0x00000004
#define SQLITE_TRANSIENT ((sqlite3_destructor_type)-1)

static void jayess_sqlite_db_finalizer(void *handle) {
    if (handle != NULL) {
        sqlite3_close_v2((sqlite3 *) handle);
    }
}

static void jayess_sqlite_stmt_finalizer(void *handle) {
    if (handle != NULL) {
        sqlite3_finalize((sqlite3_stmt *) handle);
    }
}

static void jayess_sqlite_throw_error(sqlite3 *db, const char *fallback, int code) {
    char message[512];
    const char *detail = fallback;
    if (db != NULL) {
        detail = sqlite3_errmsg(db);
    }
    if (detail == NULL || detail[0] == '\0') {
        detail = "sqlite error";
    }
    snprintf(message, sizeof(message), "%s (sqlite code %d)", detail, code);
    jayess_throw_named_error("SQLiteError", message);
}

static int jayess_sqlite_bind_index(jayess_value *index_value, const char *context) {
    double number = jayess_value_to_number(index_value);
    if (jayess_has_exception()) {
        return 0;
    }
    if (number < 1) {
        jayess_throw_type_error(context);
        return 0;
    }
    return (int) number;
}

static jayess_value *jayess_sqlite_column_value(sqlite3_stmt *stmt, int index) {
    int type = sqlite3_column_type(stmt, index);
    switch (type) {
        case SQLITE_INTEGER:
            return jayess_value_from_number((double) sqlite3_column_int64(stmt, index));
        case SQLITE_FLOAT:
            return jayess_value_from_number(sqlite3_column_double(stmt, index));
        case SQLITE_TEXT: {
            const unsigned char *text = sqlite3_column_text(stmt, index);
            return jayess_value_from_string(text != NULL ? (const char *) text : "");
        }
        case SQLITE_BLOB: {
            const void *blob = sqlite3_column_blob(stmt, index);
            int length = sqlite3_column_bytes(stmt, index);
            return jayess_value_from_bytes_copy((const unsigned char *) blob, length > 0 ? (size_t) length : 0);
        }
        case SQLITE_NULL:
        default:
            return jayess_value_null();
    }
}

static jayess_value *jayess_sqlite_row_object(sqlite3_stmt *stmt) {
    int count = sqlite3_column_count(stmt);
    int i = 0;
    jayess_object *row = jayess_object_new();
    if (row == NULL) {
        return jayess_value_undefined();
    }
    for (i = 0; i < count; i++) {
        const char *name = sqlite3_column_name(stmt, i);
        jayess_object_set_value(row, name != NULL ? name : "", jayess_sqlite_column_value(stmt, i));
    }
    return jayess_value_from_object(row);
}

static jayess_value *jayess_sqlite_row_array(sqlite3_stmt *stmt) {
    int count = sqlite3_column_count(stmt);
    int i = 0;
    jayess_array *row = jayess_array_new();
    if (row == NULL) {
        return jayess_value_undefined();
    }
    for (i = 0; i < count; i++) {
        jayess_array_push_value(row, jayess_sqlite_column_value(stmt, i));
    }
    return jayess_value_from_array(row);
}

jayess_value *jayess_sqlite_open_native(jayess_value *path_value) {
    const char *path = jayess_expect_string(path_value, "jayess_sqlite_open_native");
    sqlite3 *db = NULL;
    int rc = SQLITE_OK;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    rc = sqlite3_open_v2(path, &db, SQLITE_OPEN_READWRITE | SQLITE_OPEN_CREATE, NULL);
    if (rc != SQLITE_OK || db == NULL) {
        jayess_sqlite_throw_error(db, "failed to open sqlite database", rc);
        if (db != NULL) {
            sqlite3_close_v2(db);
        }
        return jayess_value_undefined();
    }
    return jayess_value_from_managed_native_handle("SQLiteDatabase", db, jayess_sqlite_db_finalizer);
}

jayess_value *jayess_sqlite_close_native(jayess_value *db_value) {
    jayess_expect_native_handle(db_value, "SQLiteDatabase", "jayess_sqlite_close_native");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    jayess_value_close_native_handle(db_value);
    return jayess_value_undefined();
}

jayess_value *jayess_sqlite_exec_native(jayess_value *db_value, jayess_value *sql_value) {
    sqlite3 *db = (sqlite3 *) jayess_expect_native_handle(db_value, "SQLiteDatabase", "jayess_sqlite_exec_native");
    const char *sql = jayess_expect_string(sql_value, "jayess_sqlite_exec_native");
    char *errmsg = NULL;
    int rc = SQLITE_OK;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    rc = sqlite3_exec(db, sql, NULL, NULL, &errmsg);
    if (rc != SQLITE_OK) {
        const char *detail = errmsg != NULL ? errmsg : "sqlite exec failed";
        jayess_throw_named_error("SQLiteError", detail);
        if (errmsg != NULL) {
            sqlite3_free(errmsg);
        }
        return jayess_value_undefined();
    }
    if (errmsg != NULL) {
        sqlite3_free(errmsg);
    }
    return jayess_value_undefined();
}

jayess_value *jayess_sqlite_prepare_native(jayess_value *db_value, jayess_value *sql_value) {
    sqlite3 *db = (sqlite3 *) jayess_expect_native_handle(db_value, "SQLiteDatabase", "jayess_sqlite_prepare_native");
    const char *sql = jayess_expect_string(sql_value, "jayess_sqlite_prepare_native");
    sqlite3_stmt *stmt = NULL;
    int rc = SQLITE_OK;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
    if (rc != SQLITE_OK || stmt == NULL) {
        jayess_sqlite_throw_error(db, "failed to prepare sqlite statement", rc);
        if (stmt != NULL) {
            sqlite3_finalize(stmt);
        }
        return jayess_value_undefined();
    }
    return jayess_value_from_managed_native_handle("SQLiteStatement", stmt, jayess_sqlite_stmt_finalizer);
}

jayess_value *jayess_sqlite_finalize_native(jayess_value *stmt_value) {
    jayess_expect_native_handle(stmt_value, "SQLiteStatement", "jayess_sqlite_finalize_native");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    jayess_value_close_native_handle(stmt_value);
    return jayess_value_undefined();
}

