jayess_value *jayess_sqlite_bind_blob_native(jayess_value *stmt_value, jayess_value *index_value, jayess_value *blob_value) {
    sqlite3_stmt *stmt = (sqlite3_stmt *) jayess_expect_native_handle(stmt_value, "SQLiteStatement", "jayess_sqlite_bind_blob_native");
    int index = 0;
    int rc = SQLITE_OK;
    size_t length = 0;
    unsigned char *bytes = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    index = jayess_sqlite_bind_index(index_value, "jayess_sqlite_bind_blob_native");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    bytes = jayess_value_to_bytes_copy(blob_value, &length);
    if (bytes == NULL && !jayess_has_exception()) {
        bytes = (unsigned char *) calloc(1, 1);
        length = 0;
    }
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    rc = sqlite3_bind_blob(stmt, index, bytes, (int) length, SQLITE_TRANSIENT);
    free(bytes);
    if (rc != SQLITE_OK) {
        jayess_throw_named_error("SQLiteError", "failed to bind sqlite blob");
    }
    return jayess_value_undefined();
}

jayess_value *jayess_sqlite_step_object_native(jayess_value *stmt_value) {
    sqlite3_stmt *stmt = (sqlite3_stmt *) jayess_expect_native_handle(stmt_value, "SQLiteStatement", "jayess_sqlite_step_object_native");
    int rc = SQLITE_OK;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    rc = sqlite3_step(stmt);
    if (rc == SQLITE_ROW) {
        return jayess_sqlite_row_object(stmt);
    }
    if (rc == SQLITE_DONE) {
        return jayess_value_null();
    }
    jayess_throw_named_error("SQLiteError", "sqlite statement step failed");
    return jayess_value_undefined();
}

