jayess_value *jayess_sqlite_busy_timeout_native(jayess_value *db_value, jayess_value *milliseconds_value) {
    sqlite3 *db = (sqlite3 *) jayess_expect_native_handle(db_value, "SQLiteDatabase", "jayess_sqlite_busy_timeout_native");
    double number = 0;
    int rc = SQLITE_OK;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    number = jayess_value_to_number(milliseconds_value);
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    rc = sqlite3_busy_timeout(db, (int) number);
    if (rc != SQLITE_OK) {
        jayess_throw_named_error("SQLiteError", "failed to configure sqlite busy timeout");
    }
    return jayess_value_undefined();
}
